-- 1:N  -> FK lives on the many side
ALTER TABLE order_lines ADD COLUMN order_id BIGINT REFERENCES orders(id);

-- 1:1  -> unique FK splits an optional extension out for locality
CREATE TABLE user_profiles (
    user_id   BIGINT PRIMARY KEY REFERENCES users(id),  -- PK = FK enforces 1:1
    bio       TEXT,
    avatar_url TEXT
);

-- M:N  -> associative table; PK is the pair, attributes live here
CREATE TABLE enrollments (
    student_id BIGINT NOT NULL REFERENCES students(id),
    course_id  BIGINT NOT NULL REFERENCES courses(id),
    grade      TEXT,
    enrolled_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    PRIMARY KEY (student_id, course_id)
);

// Document model (embed lines, reference customer)
{
  "_id": "order_01H9X",
  "customerId": "cust_42",        // reference: shared, updated independently
  "status": "paid",
  "placedAt": "2026-06-30T10:00:00Z",
  "lines": [                       // embed: read together, owned by the order
    { "sku": "SKU-1", "name": "Keyboard", "qty": 1, "unitPriceCents": 7999 },
    { "sku": "SKU-9", "name": "Mouse",    "qty": 2, "unitPriceCents": 2999 }
  ],
  "totalCents": 13997             // denormalized aggregate for the list view
}

// One DynamoDB table, heterogeneous items, overloaded PK/SK
[
  { "PK": "CUSTOMER#42", "SK": "PROFILE#42",
    "type": "Customer", "email": "ada@example.com", "tier": "gold" },

  { "PK": "CUSTOMER#42", "SK": "ORDER#01H9X",
    "type": "Order", "status": "paid", "totalCents": 13997,
    "GSI1PK": "STATUS#paid", "GSI1SK": "ORDER#01H9X" },

  { "PK": "ORDER#01H9X", "SK": "LINE#SKU-1",
    "type": "OrderLine", "name": "Keyboard", "qty": 1, "unitPriceCents": 7999 },

  { "PK": "ORDER#01H9X", "SK": "LINE#SKU-9",
    "type": "OrderLine", "name": "Mouse", "qty": 2, "unitPriceCents": 2999 }
]

// Access patterns satisfied by single Query calls:
//  1. Customer + all their orders : PK = CUSTOMER#42
//  2. All lines of one order      : PK = ORDER#01H9X, SK begins_with LINE#
//  3. All paid orders (via GSI1)  : GSI1PK = STATUS#paid

-- Star schema: one fact, several denormalized dimensions
CREATE TABLE dim_date (
    date_sk    INTEGER PRIMARY KEY,     -- e.g. 20260701
    full_date  DATE NOT NULL,
    day_of_week TEXT, month TEXT, quarter TEXT, year INTEGER
);
CREATE TABLE dim_product (
    product_sk BIGINT PRIMARY KEY,      -- surrogate; supports SCD Type 2
    sku        TEXT, name TEXT, category TEXT, brand TEXT   -- flattened (denormalized)
);
CREATE TABLE dim_customer (
    customer_sk BIGINT PRIMARY KEY,
    customer_id BIGINT, tier TEXT, region TEXT
);

CREATE TABLE fact_sales (
    sale_sk       BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    date_sk       INTEGER NOT NULL REFERENCES dim_date(date_sk),
    product_sk    BIGINT  NOT NULL REFERENCES dim_product(product_sk),
    customer_sk   BIGINT  NOT NULL REFERENCES dim_customer(customer_sk),
    quantity      INTEGER NOT NULL,     -- additive measure
    amount_cents  BIGINT  NOT NULL      -- additive measure
);
-- Typical query: SUM(amount_cents) by month and category
--   -> two small dimension joins + one big fact scan, no deep join chains.

